// ── MILESTONE 3: Batch Processing ──────────────────────────────────────────
// Process ALL incoming submissions rather than only the latest one.
// Each item is a separate submission; pass them all forward.
const allItems = items;

// Sort by Timestamp (newest first) so results are ordered chronologically
allItems.sort((a, b) => {
  return new Date(b.json.Timestamp) - new Date(a.json.Timestamp);
});

// Tag every item with a batch_index so downstream nodes can group results
return allItems.map((item, idx) => ({
  json: {
    ...item.json,
    batch_index: idx,
    batch_total: allItems.length
  }
}));

const input = $input.first().json;
const text = input["Assignment "] || input["Assignment"] || "";

const sections = text.split(/\n+/);
const cleanSections = sections.filter(s => s.trim() !== "");

const name = input["Name "] || input["Name"] || input["Full Name"] || input["Student Name"] || "Unknown";
const title = input["Title"] || input["Assignment Title"] || "Unknown";

return cleanSections.map(section => ({
  json: {
    section,
    name,
    title
  }
}));

const raw = $json.text || "";

let parsed;

try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : null;
} catch (e) {
  parsed = null;
}

if (!parsed) {
  return [{
    json: {
      similarity_score: 0,
      classification: "original",
      ai_generated: false,
      confidence: 0,
      flags: [],
      reason: "fallback due to parsing error"
    }
  }];
}

return [{ json: parsed }];

let totalSimilarity = 0;
let totalConfidence = 0;
let copied = 0;
let paraphrased = 0;
let original = 0;
let aiCount = 0;
let flagSet = new Set();

let verdictScores = {
  "AI_GENERATED": 5,
  "LIKELY_AI_GENERATED": 4,
  "INCONCLUSIVE": 3,
  "LIKELY_HUMAN_WRITTEN": 2,
  "HUMAN_WRITTEN": 1
};

let verdictTally = {};
let totalVerdictScore = 0;

items.forEach(item => {
  const data = item.json;
  totalSimilarity += data.similarity_score || 0;
  totalConfidence += data.confidence || 0;

  if (data.classification === "copied")      copied++;
  if (data.classification === "paraphrased") paraphrased++;
  if (data.classification === "original")    original++;
  if (data.ai_generated) aiCount++;

  if (Array.isArray(data.flags)) {
    data.flags.forEach(flag => flagSet.add(flag));
  }

  const verdict =
    data.final_verdict?.verdict ||
    (data.ai_generated ? "LIKELY_AI_GENERATED" : "LIKELY_HUMAN_WRITTEN");

  verdictTally[verdict] = (verdictTally[verdict] || 0) + 1;
  totalVerdictScore += verdictScores[verdict] || 3;
});

const count = items.length || 1;
const avgSimilarity   = Math.round(totalSimilarity / count);
const avgConfidence   = parseFloat((totalConfidence / count).toFixed(2));
const aiPercent       = count ? Math.round((aiCount / count) * 100) : 0;
const avgVerdictScore = totalVerdictScore / count;

let overallVerdict;
if (avgVerdictScore >= 4.5)      overallVerdict = "AI_GENERATED";
else if (avgVerdictScore >= 3.5) overallVerdict = "LIKELY_AI_GENERATED";
else if (avgVerdictScore >= 2.5) overallVerdict = "INCONCLUSIVE";
else if (avgVerdictScore >= 1.5) overallVerdict = "LIKELY_HUMAN_WRITTEN";
else                             overallVerdict = "HUMAN_WRITTEN";

const riskLevel =
  (aiPercent >= 70 || avgSimilarity >= 70) ? "HIGH" :
  (aiPercent >= 40 || avgSimilarity >= 45) ? "MEDIUM" :
  "LOW";

return [{
  json: {
    name:               String(items[0]?.json?.name  || items[0]?.json?.Name  || "Unknown"),
    title:              String(items[0]?.json?.title || items[0]?.json?.Title || "Unknown"),
    batch_index:        items[0]?.json?.batch_index ?? 0,
    batch_total:        items[0]?.json?.batch_total ?? 1,

    avg_similarity:     avgSimilarity,
    avg_confidence:     avgConfidence,

    total_sections:     count,
    copied_sections:    copied,
    paraphrased_sections: paraphrased,
    original_sections:  original,
    ai_sections:        aiCount,
    ai_percentage:      aiPercent,

    overall_verdict:    overallVerdict,
    verdict_breakdown:  verdictTally,
    all_flags:          Array.from(flagSet),
    risk_level:         riskLevel
  }
}];

// ── MILESTONE 3: Knowledge Map ──────────────────────────────────────────────
// Links common plagiarism patterns detected by the AI to curated educational
// resources. Implements a semantic knowledge graph as a JS object (adjacency
// list representation), per Module 3 – Modern Knowledge Representation (L12).

const KNOWLEDGE_MAP = {
  // Pattern node → { description, resources[], severity }
  "generic phrasing": {
    description: "Text uses non-specific, interchangeable language typical of AI generation.",
    resources: [
      { title: "Purdue OWL – Original Voice", url: "https://owl.purdue.edu/owl/general_writing/academic_writing/index.html" },
      { title: "Harvard – Writing with Your Own Voice", url: "https://writingcenter.fas.harvard.edu/pages/developing-thesis" }
    ],
    severity: "medium"
  },
  "repetitive sentence structure": {
    description: "Sentences follow a monotonous structural template, a strong AI signature.",
    resources: [
      { title: "MIT – Sentence Variety Guide", url: "https://writingcenter.mit.edu/guides/sentence-variety" },
      { title: "UNC – Style Tips", url: "https://writingcenter.unc.edu/tips-and-tools/style/" }
    ],
    severity: "medium"
  },
  "AI boilerplate detected": {
    description: "Stock AI phrases ('It is important to note', 'In conclusion') identified.",
    resources: [
      { title: "Academic Integrity – AI Policy", url: "https://academicintegrity.org/resources/ai-policy" },
      { title: "Turnitin – Understanding AI Writing", url: "https://www.turnitin.com/blog/how-to-recognize-ai-writing" }
    ],
    severity: "high"
  },
  "humanized_ai_detected": {
    description: "Text shows signs of AI content run through a humanization tool.",
    resources: [
      { title: "IEEE – AI Ethics & Authorship", url: "https://ethicsinaction.ieee.org/" },
      { title: "Copyleaks – Humanized AI Detection", url: "https://copyleaks.com/ai-content-detector" }
    ],
    severity: "critical"
  },
  "no unique insight": {
    description: "Submission lacks original analysis or personal perspective.",
    resources: [
      { title: "Stanford – Critical Thinking Skills", url: "https://tomprof.stanford.edu/posting/1011" },
      { title: "Yale – Developing Arguments", url: "https://poorvucenter.yale.edu/writing/graduate-writing/developing-argument" }
    ],
    severity: "medium"
  },
  "paragraph micro-pattern match": {
    description: "Every paragraph follows [Topic→Elaboration→Example→Transition] — a defining AI skeleton.",
    resources: [
      { title: "UNC – Paragraph Development", url: "https://writingcenter.unc.edu/tips-and-tools/paragraphs/" },
      { title: "Harvard – Transitioning Between Ideas", url: "https://writingcenter.fas.harvard.edu/pages/transitions" }
    ],
    severity: "high"
  },
  "copied structural pattern": {
    description: "Argument structure mirrors a known AI template.",
    resources: [
      { title: "Grammarly – Avoiding Plagiarism", url: "https://www.grammarly.com/blog/plagiarism/" },
      { title: "Cite This For Me – Academic Integrity", url: "https://www.citethisforme.com/academic-integrity" }
    ],
    severity: "high"
  },
  "absence of uncertainty": {
    description: "No hedging or epistemic humility — AI tends to assert with unwarranted certainty.",
    resources: [
      { title: "APA – Hedging in Academic Writing", url: "https://apastyle.apa.org/style-grammar-guidelines/citations/hedging" },
      { title: "Oxford – Academic English Hedging", url: "https://www.ox.ac.uk/students/academic/guidance/skills/hedging" }
    ],
    severity: "low"
  },
  "uniform sentence length": {
    description: "Lack of natural sentence rhythm; sentences are suspiciously uniform in length.",
    resources: [
      { title: "Purdue OWL – Sentence Variation", url: "https://owl.purdue.edu/owl/general_writing/mechanics/sentence_variety.html" }
    ],
    severity: "medium"
  },
  "exhaustive coverage no depth": {
    description: "Topic is broadly covered but without any depth or personal engagement.",
    resources: [
      { title: "MIT OpenCourseWare – Deep Learning to Write", url: "https://ocw.mit.edu/courses/res-21g-01-krashen-on-language-acquisition/" },
      { title: "Georgetown – Deep vs Shallow Writing", url: "https://writingcenter.georgetown.edu/developing-ideas/" }
    ],
    severity: "high"
  }
};

// ── Build knowledge map output for this submission ──────────────────────────
const flags = $input.first().json.all_flags || [];
const matchedPatterns = [];
const educationalResources = [];
const resourceUrlSet = new Set();

flags.forEach(flag => {
  const entry = KNOWLEDGE_MAP[flag];
  if (entry) {
    matchedPatterns.push({
      pattern: flag,
      description: entry.description,
      severity: entry.severity
    });
    entry.resources.forEach(r => {
      if (!resourceUrlSet.has(r.url)) {
        resourceUrlSet.add(r.url);
        educationalResources.push({ pattern: flag, ...r });
      }
    });
  }
});

// Severity priority ordering
const severityOrder = { critical: 4, high: 3, medium: 2, low: 1 };
matchedPatterns.sort((a, b) => (severityOrder[b.severity] || 0) - (severityOrder[a.severity] || 0));

return [{
  json: {
    ...$input.first().json,
    knowledge_map: {
      matched_patterns: matchedPatterns,
      educational_resources: educationalResources,
      total_patterns_matched: matchedPatterns.length,
      top_concern: matchedPatterns[0]?.pattern || "none"
    }
  }
}];

// ── MILESTONE 3: Logic Rules & Flagging Thresholds ──────────────────────────
// Implements formal IF–THEN logical rules for academic integrity decisions.
// Connects to Module 3: Logic (Lecture 10) – propositional logic applied to
// plagiarism detection thresholds.
//
// Rule schema (Horn clauses / production rules):
//   IF <antecedent(s)> THEN <consequent> [confidence_weight]

const data = $input.first().json;

const avgSimilarity   = data.avg_similarity   || 0;
const avgConfidence   = data.avg_confidence   || 0;
const aiPercent       = data.ai_percentage    || 0;
const overallVerdict  = data.overall_verdict  || "INCONCLUSIVE";
const allFlags        = data.all_flags        || [];
const copiedSections  = data.copied_sections  || 0;
const totalSections   = data.total_sections   || 1;

// ── Rule Engine ──────────────────────────────────────────────────────────────
const firedRules  = [];
let   reviewFlag  = false;
let   reviewLevel = "NONE";   // NONE | ADVISORY | REVIEW | URGENT_REVIEW
let   actionItems = [];

// R1: High similarity → flag for review
if (avgSimilarity >= 70) {
  firedRules.push({ rule: "R1", condition: "avg_similarity >= 70", consequent: "URGENT_REVIEW" });
  reviewFlag  = true;
  reviewLevel = "URGENT_REVIEW";
  actionItems.push("Immediate instructor review required — similarity exceeds 70%.");
}

// R2: AI percentage high → flag for review
if (aiPercent >= 60) {
  firedRules.push({ rule: "R2", condition: "ai_percentage >= 60", consequent: "URGENT_REVIEW" });
  reviewFlag  = true;
  if (reviewLevel !== "URGENT_REVIEW") reviewLevel = "URGENT_REVIEW";
  actionItems.push("AI-generated content detected in 60%+ of sections — escalate to academic integrity panel.");
}

// R3: Moderate similarity + AI signals → REVIEW
if (avgSimilarity >= 45 && avgSimilarity < 70 && aiPercent >= 30) {
  firedRules.push({ rule: "R3", condition: "avg_similarity 45-69 AND ai_percentage >= 30", consequent: "REVIEW" });
  reviewFlag = true;
  if (reviewLevel === "NONE" || reviewLevel === "ADVISORY") reviewLevel = "REVIEW";
  actionItems.push("Moderate similarity combined with significant AI signals — schedule instructor review.");
}

// R4: Verdict is AI_GENERATED → URGENT_REVIEW
if (overallVerdict === "AI_GENERATED") {
  firedRules.push({ rule: "R4", condition: "overall_verdict = AI_GENERATED", consequent: "URGENT_REVIEW" });
  reviewFlag  = true;
  reviewLevel = "URGENT_REVIEW";
  actionItems.push("Overall verdict is AI_GENERATED — student interview recommended.");
}

// R5: LIKELY_AI_GENERATED with confidence > 0.7 → REVIEW
if (overallVerdict === "LIKELY_AI_GENERATED" && avgConfidence > 0.7) {
  firedRules.push({ rule: "R5", condition: "verdict=LIKELY_AI_GENERATED AND confidence > 0.7", consequent: "REVIEW" });
  reviewFlag = true;
  if (reviewLevel === "NONE" || reviewLevel === "ADVISORY") reviewLevel = "REVIEW";
  actionItems.push("High-confidence AI likelihood — advisory review and discussion with student.");
}

// R6: Critical flag present (humanized_ai_detected) → URGENT_REVIEW
if (allFlags.includes("humanized_ai_detected")) {
  firedRules.push({ rule: "R6", condition: "flag: humanized_ai_detected present", consequent: "URGENT_REVIEW" });
  reviewFlag  = true;
  reviewLevel = "URGENT_REVIEW";
  actionItems.push("Humanization tool usage detected — treat as deliberate academic misconduct.");
}

// R7: Copied section ratio > 50% → REVIEW
const copiedRatio = totalSections > 0 ? copiedSections / totalSections : 0;
if (copiedRatio > 0.5) {
  firedRules.push({ rule: "R7", condition: "copied_sections / total_sections > 0.5", consequent: "REVIEW" });
  reviewFlag = true;
  if (reviewLevel === "NONE" || reviewLevel === "ADVISORY") reviewLevel = "REVIEW";
  actionItems.push("More than 50% of sections classified as copied — potential direct plagiarism.");
}

// R8: Low similarity + HUMAN_WRITTEN → advisory only
if (avgSimilarity < 20 && overallVerdict === "HUMAN_WRITTEN" && !reviewFlag) {
  firedRules.push({ rule: "R8", condition: "avg_similarity < 20 AND verdict=HUMAN_WRITTEN", consequent: "PASS" });
  reviewLevel = "NONE";
  actionItems.push("Submission appears original. No review required.");
}

// R9: Advisory — moderate signals but nothing definitive
if (!reviewFlag && (avgSimilarity >= 20 || aiPercent >= 20)) {
  firedRules.push({ rule: "R9", condition: "avg_similarity >= 20 OR ai_percentage >= 20", consequent: "ADVISORY" });
  reviewLevel = "ADVISORY";
  actionItems.push("Borderline signals present — document for future reference.");
}

return [{
  json: {
    ...$input.first().json,
    logic_rules: {
      fired_rules:   firedRules,
      review_flag:   reviewFlag,
      review_level:  reviewLevel,
      action_items:  [...new Set(actionItems)],
      rules_applied: firedRules.length
    }
  }
}];

// ── MILESTONE 3: Confidence Level Enrichment ────────────────────────────────
// Applies probability / Bayesian reasoning concepts from Module 3:
// Reasoning Under Uncertainty (Lecture 13).
//
// Computes a composite Bayesian-inspired confidence score combining:
//   P(plagiarism | evidence) ∝ P(evidence | plagiarism) × P(plagiarism)
// implemented as a weighted evidence accumulation model.

const data = $input.first().json;

const rawConfidence   = data.avg_confidence   || 0;
const avgSimilarity   = data.avg_similarity   || 0;
const aiPercent       = data.ai_percentage    || 0;
const overallVerdict  = data.overall_verdict  || "INCONCLUSIVE";
const allFlags        = data.all_flags        || [];
const totalSections   = data.total_sections   || 1;
const reviewLevel     = data.logic_rules?.review_level || "NONE";

// ── Prior probability of plagiarism (base rate) ──────────────────────────────
// Academic literature suggests ~15–20% base rate; we use 0.18 as prior
const P_PRIOR = 0.18;

// ── Likelihood ratios (evidence weights) ────────────────────────────────────
// How much each evidence piece updates P(plagiarism)
let likelihoodRatio = 1.0;

// Evidence: average LLM confidence
if (rawConfidence > 0.85)      likelihoodRatio *= 8.0;
else if (rawConfidence > 0.70) likelihoodRatio *= 4.5;
else if (rawConfidence > 0.50) likelihoodRatio *= 2.5;
else if (rawConfidence > 0.30) likelihoodRatio *= 1.5;

// Evidence: similarity score
if (avgSimilarity >= 70)       likelihoodRatio *= 7.0;
else if (avgSimilarity >= 45)  likelihoodRatio *= 3.5;
else if (avgSimilarity >= 25)  likelihoodRatio *= 1.8;

// Evidence: AI percentage
if (aiPercent >= 70)           likelihoodRatio *= 6.0;
else if (aiPercent >= 50)      likelihoodRatio *= 3.0;
else if (aiPercent >= 30)      likelihoodRatio *= 1.5;

// Evidence: verdict
const verdictBoost = {
  "AI_GENERATED":        9.0,
  "LIKELY_AI_GENERATED": 4.0,
  "INCONCLUSIVE":        1.0,
  "LIKELY_HUMAN_WRITTEN":0.4,
  "HUMAN_WRITTEN":       0.1
};
likelihoodRatio *= (verdictBoost[overallVerdict] || 1.0);

// Evidence: critical flags
if (allFlags.includes("humanized_ai_detected"))  likelihoodRatio *= 5.0;
if (allFlags.includes("AI boilerplate detected")) likelihoodRatio *= 2.5;
if (allFlags.includes("paragraph micro-pattern match")) likelihoodRatio *= 2.0;

// Evidence: sample size (more sections → more reliable)
const sampleFactor = Math.min(1.0, 0.4 + (totalSections / 20) * 0.6);

// ── Bayesian posterior ───────────────────────────────────────────────────────
// P(plagiarism | evidence) = (prior × LR) / (prior × LR + (1-prior))
const posterior_raw = (P_PRIOR * likelihoodRatio) /
                      (P_PRIOR * likelihoodRatio + (1 - P_PRIOR));
const posteriorConfidence = parseFloat(
  Math.min(0.99, posterior_raw * sampleFactor).toFixed(3)
);

// ── Confidence tier classification ───────────────────────────────────────────
let confidenceTier, tierLabel, tierColor;
if (posteriorConfidence >= 0.85) {
  confidenceTier = 4; tierLabel = "VERY_HIGH"; tierColor = "#d32f2f";
} else if (posteriorConfidence >= 0.65) {
  confidenceTier = 3; tierLabel = "HIGH";      tierColor = "#f57c00";
} else if (posteriorConfidence >= 0.40) {
  confidenceTier = 2; tierLabel = "MODERATE";  tierColor = "#fbc02d";
} else if (posteriorConfidence >= 0.20) {
  confidenceTier = 1; tierLabel = "LOW";       tierColor = "#388e3c";
} else {
  confidenceTier = 0; tierLabel = "VERY_LOW";  tierColor = "#1976d2";
}

// ── Uncertainty quantification ───────────────────────────────────────────────
// Epistemic uncertainty: high when sample is small or evidence is mixed
const epistemicUncertainty = parseFloat(
  Math.max(0, 1 - sampleFactor - rawConfidence * 0.3).toFixed(3)
);

return [{
  json: {
    ...data,
    confidence_analysis: {
      bayesian_posterior:    posteriorConfidence,
      prior_probability:     P_PRIOR,
      likelihood_ratio:      parseFloat(likelihoodRatio.toFixed(3)),
      sample_reliability:    parseFloat(sampleFactor.toFixed(3)),
      epistemic_uncertainty: epistemicUncertainty,
      confidence_tier:       confidenceTier,
      confidence_tier_label: tierLabel,
      confidence_tier_color: tierColor,
      interpretation: `${Math.round(posteriorConfidence * 100)}% posterior probability of plagiarism/AI-generation based on converging evidence.`
    }
  }
}];
